from litellm import Router

router = Router(
    model_list=[
        {
            "model_name": "gpt-5.5",
            "litellm_params": {"model": "gpt-5.5", "api_key": "..."},
        },
        {
            "model_name": "claude-sonnet-4-6",
            "litellm_params": {"model": "anthropic/claude-sonnet-4-6", "api_key": "..."},
        },
    ],
    fallbacks=[{"gpt-5.5": ["claude-sonnet-4-6"]}],
    context_window_fallbacks=[{"gpt-5.5": ["claude-sonnet-4-6"]}],
    num_retries=3,
    retry_after=5,          # seconds between retries
    cooldown_time=60,        # mark deployment unhealthy for 60 s after failure
    set_verbose=False,
)

response = await router.acompletion(
    model="gpt-5.5",
    messages=[{"role": "user", "content": "Summarise this document."}],
)

import time, random
from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception

RETRYABLE = {429, 500, 502, 503, 504}

def is_retryable(exc: Exception) -> bool:
    status = getattr(exc, "status_code", None)
    return status in RETRYABLE

@retry(
    retry=retry_if_exception(is_retryable),
    wait=wait_exponential(multiplier=0.5, min=0.5, max=10),
    stop=stop_after_attempt(3),
    reraise=True,
)
async def call_llm(client, messages):
    try:
        return await client.chat.completions.create(
            model="gpt-5.5",
            messages=messages,
            timeout=30,
        )
    except Exception as exc:
        # Honour Retry-After if present
        retry_after = getattr(exc, "headers", {}).get("Retry-After")
        if retry_after:
            time.sleep(float(retry_after) + random.uniform(0, 0.5))
        raise
